import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const PostProductPage = () => {
  const navigate = useNavigate();
  
  // Các biến để lưu thông tin người dùng nhập vào
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [image, setImage] = useState('');
  const [description, setDescription] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault(); // Chặn việc load lại trang

    // Kiểm tra dữ liệu
    if (!name || !price || !image) {
      alert('Vui lòng điền đầy đủ thông tin!');
      return;
    }

    try {
      // Gửi dữ liệu xuống Backend (Server)
      await axios.post('http://localhost:5000/api/products', {
        name,
        price,
        image,
        description
      });

      alert('Đăng tin thành công!');
      navigate('/'); // Quay về trang chủ để ngắm thành quả
    } catch (error) {
      console.error(error);
      alert('Có lỗi xảy ra, vui lòng thử lại.');
    }
  };

  return (
    <div className="container py-5">
      <div className="card shadow mx-auto" style={{ maxWidth: '600px' }}>
        <div className="card-header bg-chotot text-dark fw-bold text-center">
          ĐĂNG TIN MỚI
        </div>
        <div className="card-body p-4">
          <form onSubmit={handleSubmit}>
            
            {/* 1. TÊN SẢN PHẨM */}
            <div className="mb-3">
              <label className="form-label fw-bold">Tên sản phẩm</label>
              <input 
                type="text" 
                className="form-control" 
                placeholder="Ví dụ: Iphone 11 Promax cũ..." 
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>

            {/* 2. GIÁ BÁN */}
            <div className="mb-3">
              <label className="form-label fw-bold">Giá bán (VNĐ)</label>
              <input 
                type="number" 
                className="form-control" 
                placeholder="Ví dụ: 5000000" 
                value={price}
                onChange={(e) => setPrice(e.target.value)}
              />
            </div>

            {/* 3. LINK ẢNH (Dùng link tạm) */}
            <div className="mb-3">
              <label className="form-label fw-bold">Link hình ảnh</label>
              <input 
                type="text" 
                className="form-control" 
                placeholder="Dán link ảnh từ mạng vào đây..." 
                value={image}
                onChange={(e) => setImage(e.target.value)}
              />
              <small className="text-muted">Mẹo: Lên Google tìm ảnh -> Chuột phải "Sao chép địa chỉ hình ảnh" -> Dán vào đây.</small>
            </div>
            
            {/* Xem trước ảnh */}
            {image && (
              <div className="mb-3 text-center">
                <img src={image} alt="Preview" style={{maxHeight: '150px', borderRadius: '8px'}} />
              </div>
            )}

            {/* 4. MÔ TẢ */}
            <div className="mb-3">
              <label className="form-label fw-bold">Mô tả chi tiết</label>
              <textarea 
                className="form-control" 
                rows="4" 
                placeholder="Tình trạng, màu sắc, nơi mua..."
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              ></textarea>
            </div>

            <button type="submit" className="btn btn-chotot w-100 fw-bold py-2">ĐĂNG NGAY</button>
            <button type="button" className="btn btn-light w-100 mt-2" onClick={() => navigate('/')}>Hủy bỏ</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default PostProductPage;
